# Zero UUID used by Bambu printers for empty/unset tray_uuid
_ZERO_UUID = "00000000000000000000000000000000"


def _resolve_spool_tag(tray_info: dict) -> str:
    """Get the best spool identifier from tray info (prefer tray_uuid, fallback to filament_id)."""
    tray_uuid = tray_info.get("tray_uuid")
    if tray_uuid and tray_uuid != _ZERO_UUID:
        return tray_uuid
    # Fallback to filament_id if tray_uuid is not set or zero
    filament_id = tray_info.get("filament_id")
    if filament_id:
        return filament_id
    return ""


def _parse_gcode_line(line: str) -> dict:
    """Parse a G-code line into a dict of commands and parameters."""
    parts = line.strip().split()
    if not parts:
        return {}
    cmd = parts[0]
    params = {}
    for part in parts[1:]:
        if len(part) < 2:
            continue
        key = part[0]
        try:
            value = float(part[1:])
        except ValueError:
            value = part[1:]
        params[key] = value
    return {"cmd": cmd, "params": params}


def _extract_filament_usage(gcode_lines: list) -> dict:
    """Extract filament usage per tool from G-code lines."""
    usage = {}
    for line in gcode_lines:
        parsed = _parse_gcode_line(line)
        if not parsed:
            continue
        cmd = parsed.get("cmd")
        params = parsed.get("params", {})
        if cmd == "G1" and "E" in params:
            # Assume tool 0 if no tool change
            tool = usage.get("current_tool", 0)
            usage[tool] = usage.get(tool, 0) + params["E"]
        elif cmd == "T":
            try:
                tool_num = int(params.get("", 0))
                usage["current_tool"] = tool_num
            except Exception:
                pass
    # Remove current_tool key
    usage.pop("current_tool", None)
    return usage
